// Simple GraphQL formatter
const tokens = input.replace(/,\s*/g, '\n').split('').reduce((acc, ch) => {
  if (ch === '{') { acc.push(ch); acc.push('__NEWLINE__'); }
  else if (ch === '}') { acc.push('__NEWLINE__'); acc.push(ch); acc.push('__NEWLINE__'); }
  else acc.push(ch);
  return acc;
}, []).join('');

const rawLines = tokens.split('__NEWLINE__').map(l => l.trim()).filter((l, i, a) => l || (a[i-1] && a[i+1]));
let indent = 0;
const out = [];
for (const line of rawLines) {
  if (!line) continue;
  if (line.startsWith('}')) indent = Math.max(0, indent - 1);
  out.push('  '.repeat(indent) + line);
  if (line.endsWith('{')) indent++;
}
// Clean up comments
const result = out.join('\n').replace(/\n{3,}/g, '\n\n');
return { output: result, outputLanguage: 'graphql' };
